import type { ProjectGitCommit } from '@motivation/shared';
import stylesText from './project-git-log.css?inline';
import { cssStyleSheet } from '../../../../utils/css.js';

const styles = cssStyleSheet(stylesText);
import { ProjectsService } from '../../../../services/projects.service.js';

const template = document.createElement('template');
template.innerHTML = `
<div class="state" id="loading">Loading git activity…</div>
<div class="state" id="error" hidden></div>
<ul class="git-list" id="commits"></ul>
<template id="item-template">
    <li class="git-entry">
        <details class="git-item">
            <summary class="item-summary">
                <span class="item-text">
                    <span class="item-id item-hash"></span>
                    <span class="item-title"></span>
                </span>
                <span class="item-id item-date"></span>
            </summary>
            <div class="item-body">
                <p class="item-meta"></p>
                <p class="item-detail item-full-hash"></p>
            </div>
        </details>
    </li>
</template>
`;

export class ProjectGitLog extends HTMLElement {
    private shadowRootRef: ShadowRoot;
    private loadingEl!: HTMLElement;
    private errorEl!: HTMLElement;
    private commitsEl!: HTMLElement;
    private itemTemplateEl!: HTMLTemplateElement;
    private loadSequence = 0;

    static get observedAttributes(): string[] {
        return ['project-id'];
    }

    constructor() {
        super();
        this.shadowRootRef = this.attachShadow({ mode: 'open' });
        this.shadowRootRef.adoptedStyleSheets = [styles];
        this.shadowRootRef.appendChild(template.content.cloneNode(true));
    }

    connectedCallback(): void {
        this.loadingEl = this.shadowRootRef.getElementById('loading') as HTMLElement;
        this.errorEl = this.shadowRootRef.getElementById('error') as HTMLElement;
        this.commitsEl = this.shadowRootRef.getElementById('commits') as HTMLElement;
        this.itemTemplateEl = this.shadowRootRef.getElementById('item-template') as HTMLTemplateElement;
        void this.loadData();
    }

    attributeChangedCallback(): void {
        if (!this.isConnected || !this.loadingEl) return;
        void this.loadData();
    }

    private async loadData(): Promise<void> {
        const projectId = this.getAttribute('project-id');
        if (projectId !== 'motivation' || !this.loadingEl) return;

        const currentLoad = ++this.loadSequence;
        this.loadingEl.hidden = false;
        this.errorEl.hidden = true;
        this.commitsEl.hidden = true;

        try {
            const response = await ProjectsService.fetchMotivationGitLog();
            if (currentLoad !== this.loadSequence || !this.isConnected || !this.loadingEl) return;
            this.renderCommits(response.commits);
        } catch (error) {
            console.error('Failed to load git activity', error);
            if (currentLoad !== this.loadSequence || !this.isConnected || !this.loadingEl) return;
            this.loadingEl.hidden = true;
            this.errorEl.hidden = false;
            this.errorEl.textContent = 'Failed to load git activity.';
        }
    }

    private renderCommits(commits: ProjectGitCommit[]): void {
        this.commitsEl.replaceChildren(...commits.map((commit) => {
            const fragment = this.itemTemplateEl.content.cloneNode(true) as DocumentFragment;
            (fragment.querySelector('.item-hash') as HTMLElement).textContent = commit.shortHash;
            (fragment.querySelector('.item-date') as HTMLElement).textContent = commit.committedAt.slice(0, 10);
            (fragment.querySelector('.item-title') as HTMLElement).textContent = commit.subject;
            (fragment.querySelector('.item-meta') as HTMLElement).textContent = `Author: ${commit.authorName}`;
            (fragment.querySelector('.item-full-hash') as HTMLElement).textContent = `Full hash: ${commit.hash}`;
            return fragment;
        }));
        this.loadingEl.hidden = true;
        this.errorEl.hidden = true;
        this.commitsEl.hidden = false;
    }
}

if (!customElements.get('project-git-log')) {
    customElements.define('project-git-log', ProjectGitLog);
}
